import sys
from pathlib import Path


def resolve_value(v, ctx):
    """Résout [x] -> ctx['x'], sinon renvoie v."""
    if isinstance(v, str) and v.startswith("[") and v.endswith("]"):
        key = v[1:-1]
        return ctx.get(key)
    return v


def to_number(v, ctx):
    """
    Transforme v en nombre si possible :
    - [a]  -> ctx['a']
    - "a"  -> ctx['a'] si numérique
    - "2"  -> 2.0
    - "12.3" -> 12.3
    Sinon renvoie la valeur résolue telle quelle.
    """
    v_resolved = resolve_value(v, ctx)

    if isinstance(v_resolved, (int, float)):
        return float(v_resolved)

    if isinstance(v_resolved, str):
        s = v_resolved.strip()

        # nom de variable dans le contexte
        if s in ctx and isinstance(ctx[s], (int, float)):
            return float(ctx[s])

        # tentatives de cast direct
        try:
            return float(s)
        except ValueError:
            pass

        # dernier recours : extraction des chiffres
        digits = "".join(ch for ch in s if ch in "0123456789.-")
        if digits not in ("", "-", ".", "-.", ".-"):
            try:
                return float(digits)
            except Exception:
                pass

        return v_resolved

    return v_resolved


def apply_formula(formula_ref, args, ctx):
    left = to_number(args.get("left"), ctx)
    right = to_number(args.get("right"), ctx)

    if formula_ref == "MUL":
        return left * right
    if formula_ref == "ADD":
        return left + right
    if formula_ref == "DIV":
        return left / right

    raise ValueError(f"Unknown formula_ref: {formula_ref}")


def pick_node(logic):
    """
    Essaie de trouver le node de logique principal, quelle que soit la forme :
    - { "id": "...", "steps": [...] }
    - { "Logic": { ... } }
    - { "<id>": { "steps": [...] } }
    - etc.
    """
    # cas simple : un seul node avec id + steps
    if isinstance(logic, dict) and "steps" in logic:
        return logic

    # wrapper Logic
    if isinstance(logic, dict) and "Logic" in logic and isinstance(logic["Logic"], dict):
        inner = logic["Logic"]
        for v in inner.values():
            if isinstance(v, dict) and "steps" in v:
                return v

    # sinon, on prend le premier dict qui a des steps
    if isinstance(logic, dict):
        for v in logic.values():
            if isinstance(v, dict) and "steps" in v:
                return v

    raise ValueError("Aucun node avec 'steps' trouvé dans Logic.json")


def run_logic(logic_path, inputs):
    logic = json.loads(Path(logic_path).read_text(encoding="utf-8"))
    node = pick_node(logic)

    ctx = dict(inputs)
    assigned_order = []

    for step in node.get("steps", []):
        formula_ref = step.get("formula_ref")
        if not formula_ref:
            continue
        args = step.get("args", {}) or {}
        assign = step.get("assign")
        value = apply_formula(formula_ref, args, ctx)
        if assign:
            ctx[assign] = value
            assigned_order.append(assign)

    # bloc return explicite ?
    ret = {}
    return_block = node.get("return")
    if isinstance(return_block, dict) and return_block:
        for out_name, expr in return_block.items():
            ret[out_name] = resolve_value(expr, ctx)
        return ret

    # sinon : on essaie des noms standard
    for candidate in ["score", "z", "result", "value"]:
        if candidate in ctx:
            ret[candidate] = ctx[candidate]
            return ret

    # sinon : dernière variable assignée
    if assigned_order:
        last = assigned_order[-1]
        ret[last] = ctx.get(last)
        return ret

    # vraiment rien ? on renvoie tout le contexte
    return ctx


if __name__ == "__main__":
    if len(sys.argv) < 6:
        print("usage: python logic_executor.py Logic.json ComputeScoreLogic a b c")
        sys.exit(1)

    logic_path = sys.argv[1]
    # on ignore logic_id, on se débrouille tout seul
    _logic_id = sys.argv[2]
